using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut = new();

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();

    #region CreateOrder — Happy Path

    [TestMethod]
    public void CreateOrder_ValidInputs_ReturnsOrderWithCorrectProperties()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreSame(items, order.Items);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
    }

    [TestMethod]
    public void CreateOrder_SingleItem_CalculatesTotalCorrectly()
    {
        // Arrange — price * quantity = 9.99 * 3 = 29.97
        var items = CreateItems(("Gadget", 9.99m, 3));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(29.97m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_SumsAllItemTotals()
    {
        // Arrange — (5 * 2) + (3 * 4) = 10 + 12 = 22
        var items = CreateItems(("A", 5.00m, 2), ("B", 3.00m, 4));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(22.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = CreateItems(("Item", 1.00m, 1));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_GeneratesUniqueIds()
    {
        // Arrange
        var items = CreateItems(("Item", 1.00m, 1));

        // Act
        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion

    #region CreateOrder — Error Cases

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Item", 1.00m, 1));
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() => _sut.CreateOrder("cust-1", []));
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = CreateItems(("Item", 5.00m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        // Act
        var found = _sut.GetOrder(created.Id);

        // Assert
        Assert.AreSame(created, found);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        Assert.IsNull(_sut.GetOrder("does-not-exist"));
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsAllMatchingOrders()
    {
        // Arrange
        var items = CreateItems(("Item", 1.00m, 1));
        var order1 = _sut.CreateOrder("cust-A", items);
        var order2 = _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-B", items); // different customer

        // Act
        var results = _sut.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.AreEqual(2, results.Count);
        Assert.IsTrue(results.Contains(order1));
        Assert.IsTrue(results.Contains(order2));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var results = _sut.GetOrdersByCustomer("unknown");

        Assert.AreEqual(0, results.Count);
    }

    #endregion
}

