        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreSame(items, order.Items);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
    }

    [TestMethod]
    public void CreateOrder_SingleItem_CalculatesTotalCorrectly()
    {
        // Arrange — price * quantity = 9.99 * 3 = 29.97
        var items = CreateItems(("Gadget", 9.99m, 3));

